# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory backend for managing users, projects, tasks,
messaging, performance metrics, and reporting.

Design overview
---------------
* A single shared ``_State`` object owns the RLock, the time source, the
  global monotonic id counter, and every backing store / index.
* Six repository/service objects (``users``, ``projects``, ``tasks``,
  ``messages``, ``performance``, ``reports``) all share that same state and
  expose ``_lock`` pointing at the one shared ``threading.RLock``.
* The manager delegates every public operation to a repository/service.
* All public operations acquire the shared reentrant lock, and all getters
  return deep copies so callers cannot mutate internal state.

Standard library only. ASCII only. Python 3.12.
"""

from __future__ import annotations

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional, Tuple


# ---------------------------------------------------------------------------
# Enums
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    MEMBER = "member"
    ADMIN = "admin"
    MANAGER = "manager"
    VIEWER = "viewer"


class ReportFormat(Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base error for all team collaboration failures."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Dataclasses (mutable)
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: List[Attachment]
    created_at: datetime
    edited_at: Optional[datetime]


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Sentinel for "argument not provided" in update methods
# ---------------------------------------------------------------------------
class _Unset:
    """Sentinel singleton distinguishing "not provided" from ``None``."""

    _instance = None

    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
        return cls._instance

    def __repr__(self):
        return "UNSET"


UNSET = _Unset()


# ---------------------------------------------------------------------------
# Shared state
# ---------------------------------------------------------------------------
class _State:
    """Holds all shared, lock-guarded state for the collaboration manager."""

    def __init__(self, now: Callable[[], datetime]):
        self.lock = threading.RLock()
        self.now = now
        self._next_id = 1

        # Primary stores keyed by id.
        self.users: Dict[int, User] = {}
        self.projects: Dict[int, Project] = {}
        self.tasks: Dict[int, Task] = {}
        self.messages: Dict[int, Message] = {}
        self.ratings: Dict[int, Rating] = {}

        # Secondary indexes.
        self.username_index: Dict[str, int] = {}
        self.email_index: Dict[str, int] = {}
        self.tasks_by_project: Dict[int, set] = {}
        self.tasks_by_assignee: Dict[int, set] = {}
        self.messages_by_project: Dict[int, set] = {}
        self.messages_by_task: Dict[int, set] = {}
        self.ratings_by_ratee: Dict[int, set] = {}

    def new_id(self) -> int:
        """Return the next globally unique id (caller must hold the lock)."""
        value = self._next_id
        self._next_id += 1
        return value


# ---------------------------------------------------------------------------
# Validation helpers
# ---------------------------------------------------------------------------
def _require_non_empty(value: str, label: str) -> str:
    if not isinstance(value, str) or value.strip() == "":
        raise ValidationError("{0} must be a non-empty string".format(label))
    return value


def _require_valid_email(value: str) -> str:
    if not isinstance(value, str) or value.strip() == "" or "@" not in value:
        raise ValidationError("email must be non-empty and contain '@'")
    return value


# ---------------------------------------------------------------------------
# User repository
# ---------------------------------------------------------------------------
class _UserRepository:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def register(self, username, email, role=UserRole.MEMBER) -> User:
        with self._lock:
            s = self._state
            _require_non_empty(username, "username")
            _require_valid_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if username in s.username_index:
                raise DuplicateError("username already exists")
            if email in s.email_index:
                raise DuplicateError("email already exists")
            user = User(
                id=s.new_id(),
                username=username,
                email=email,
                role=role,
                created_at=s.now(),
            )
            s.users[user.id] = user
            s.username_index[username] = user.id
            s.email_index[email] = user.id
            return copy.deepcopy(user)

    def _get_raw(self, user_id: int) -> User:
        user = self._state.users.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def get(self, user_id: int) -> User:
        with self._lock:
            return copy.deepcopy(self._get_raw(user_id))

    def list(self) -> List[User]:
        with self._lock:
            ordered = sorted(self._state.users.values(), key=lambda u: u.id)
            return [copy.deepcopy(u) for u in ordered]

    def update(self, user_id, username=UNSET, email=UNSET, role=UNSET) -> User:
        with self._lock:
            s = self._state
            user = self._get_raw(user_id)

            if username is not UNSET:
                _require_non_empty(username, "username")
                existing = s.username_index.get(username)
                if existing is not None and existing != user_id:
                    raise DuplicateError("username already exists")
            if email is not UNSET:
                _require_valid_email(email)
                existing = s.email_index.get(email)
                if existing is not None and existing != user_id:
                    raise DuplicateError("email already exists")
            if role is not UNSET and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not UNSET and username != user.username:
                del s.username_index[user.username]
                s.username_index[username] = user_id
                user.username = username
            if email is not UNSET and email != user.email:
                del s.email_index[user.email]
                s.email_index[email] = user_id
                user.email = email
            if role is not UNSET:
                user.role = role
            return copy.deepcopy(user)

    def delete(self, user_id: int) -> None:
        with self._lock:
            s = self._state
            user = self._get_raw(user_id)
            for project in s.projects.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project")
            assigned_ids = list(s.tasks_by_assignee.get(user_id, set()))
            for task_id in assigned_ids:
                task = s.tasks.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has a non-completed task")
            # Clear the dangling assignee_id on the user's (completed) tasks so
            # the invariant "every task.assignee_id references an existing user"
            # holds after deletion.
            for task_id in assigned_ids:
                task = s.tasks.get(task_id)
                if task is not None:
                    task.assignee_id = None
            del s.users[user_id]
            s.username_index.pop(user.username, None)
            s.email_index.pop(user.email, None)
            s.tasks_by_assignee.pop(user_id, None)


# ---------------------------------------------------------------------------
# Project repository
# ---------------------------------------------------------------------------
class _ProjectRepository:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def _get_raw(self, project_id: int) -> Project:
        project = self._state.projects.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def create(self, name, start_date, end_date, owner_id, description="") -> Project:
        with self._lock:
            s = self._state
            if owner_id not in s.users:
                raise NotFoundError("owner {0} not found".format(owner_id))
            _require_non_empty(name, "name")
            if end_date < start_date:
                raise ValidationError("end_date must not precede start_date")
            project = Project(
                id=s.new_id(),
                name=name,
                description=description,
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=s.now(),
            )
            s.projects[project.id] = project
            return copy.deepcopy(project)

    def get(self, project_id: int) -> Project:
        with self._lock:
            return copy.deepcopy(self._get_raw(project_id))

    def list(self) -> List[Project]:
        with self._lock:
            ordered = sorted(self._state.projects.values(), key=lambda p: p.id)
            return [copy.deepcopy(p) for p in ordered]

    def update(self, project_id, name=UNSET, description=UNSET,
               start_date=UNSET, end_date=UNSET) -> Project:
        with self._lock:
            project = self._get_raw(project_id)
            if name is not UNSET:
                _require_non_empty(name, "name")
            effective_start = project.start_date if start_date is UNSET else start_date
            effective_end = project.end_date if end_date is UNSET else end_date
            if effective_end < effective_start:
                raise ValidationError("end_date must not precede start_date")
            if name is not UNSET:
                project.name = name
            if description is not UNSET:
                project.description = description
            if start_date is not UNSET:
                project.start_date = start_date
            if end_date is not UNSET:
                project.end_date = end_date
            return copy.deepcopy(project)

    def delete(self, project_id: int) -> None:
        with self._lock:
            s = self._state
            self._get_raw(project_id)

            task_ids = list(s.tasks_by_project.get(project_id, set()))
            for task_id in task_ids:
                task = s.tasks.pop(task_id, None)
                if task is not None and task.assignee_id is not None:
                    bucket = s.tasks_by_assignee.get(task.assignee_id)
                    if bucket is not None:
                        bucket.discard(task_id)
                # Remove messages attached to this task.
                msg_ids = list(s.messages_by_task.get(task_id, set()))
                for msg_id in msg_ids:
                    s.messages.pop(msg_id, None)
                s.messages_by_task.pop(task_id, None)
            s.tasks_by_project.pop(project_id, None)

            msg_ids = list(s.messages_by_project.get(project_id, set()))
            for msg_id in msg_ids:
                s.messages.pop(msg_id, None)
            s.messages_by_project.pop(project_id, None)

            del s.projects[project_id]


# ---------------------------------------------------------------------------
# Task repository
# ---------------------------------------------------------------------------
class _TaskRepository:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def _get_raw(self, task_id: int) -> Task:
        task = self._state.tasks.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def _require_project(self, project_id: int) -> Project:
        project = self._state.projects.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _require_user(self, user_id: int) -> None:
        if user_id not in self._state.users:
            raise NotFoundError("user {0} not found".format(user_id))

    def _set_assignee(self, task: Task, new_assignee: Optional[int]) -> None:
        s = self._state
        old = task.assignee_id
        if old is not None:
            bucket = s.tasks_by_assignee.get(old)
            if bucket is not None:
                bucket.discard(task.id)
        task.assignee_id = new_assignee
        if new_assignee is not None:
            s.tasks_by_assignee.setdefault(new_assignee, set()).add(task.id)

    def create(self, project_id, title, assignee_id=None, deadline=None) -> Task:
        with self._lock:
            s = self._state
            project = self._require_project(project_id)
            if assignee_id is not None:
                self._require_user(assignee_id)
            _require_non_empty(title, "title")
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline before project start")
            task = Task(
                id=s.new_id(),
                project_id=project_id,
                title=title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=None,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=s.now(),
            )
            s.tasks[task.id] = task
            s.tasks_by_project.setdefault(project_id, set()).add(task.id)
            if assignee_id is not None:
                self._set_assignee(task, assignee_id)
            return copy.deepcopy(task)

    def get(self, task_id: int) -> Task:
        with self._lock:
            return copy.deepcopy(self._get_raw(task_id))

    def list_by_project(self, project_id: int) -> List[Task]:
        with self._lock:
            s = self._state
            self._require_project(project_id)
            ids = s.tasks_by_project.get(project_id, set())
            ordered = sorted(
                (s.tasks[i] for i in ids if i in s.tasks), key=lambda t: t.id
            )
            return [copy.deepcopy(t) for t in ordered]

    def list_by_assignee(self, assignee_id: int) -> List[Task]:
        with self._lock:
            s = self._state
            self._require_user(assignee_id)
            ids = s.tasks_by_assignee.get(assignee_id, set())
            ordered = sorted(
                (s.tasks[i] for i in ids if i in s.tasks), key=lambda t: t.id
            )
            return [copy.deepcopy(t) for t in ordered]

    def assign(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self._get_raw(task_id)
            self._require_user(assignee_id)
            self._set_assignee(task, assignee_id)
            return copy.deepcopy(task)

    def reassign(self, task_id, new_assignee_id) -> Task:
        return self.assign(task_id, new_assignee_id)

    def unassign(self, task_id) -> Task:
        with self._lock:
            task = self._get_raw(task_id)
            self._set_assignee(task, None)
            return copy.deepcopy(task)

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            s = self._state
            task = self._get_raw(task_id)
            if deadline is not None:
                project = s.projects.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline before project start")
            task.deadline = deadline
            return copy.deepcopy(task)

    def update_status(self, task_id, status) -> Task:
        with self._lock:
            s = self._state
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            task = self._get_raw(task_id)
            now = s.now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            task.status = status
            return copy.deepcopy(task)


# ---------------------------------------------------------------------------
# Message repository
# ---------------------------------------------------------------------------
class _MessageRepository:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def _get_raw(self, message_id: int) -> Message:
        message = self._state.messages.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    def post(self, author_id, body, project_id=None, task_id=None,
             parent_id=None, attachments=None) -> Message:
        with self._lock:
            s = self._state
            if author_id not in s.users:
                raise NotFoundError("author {0} not found".format(author_id))
            if project_id is None and task_id is None:
                raise ValidationError("a project_id or task_id is required")
            if project_id is not None and task_id is not None:
                raise ValidationError("only one of project_id/task_id allowed")
            if project_id is not None and project_id not in s.projects:
                raise NotFoundError("project {0} not found".format(project_id))
            if task_id is not None and task_id not in s.tasks:
                raise NotFoundError("task {0} not found".format(task_id))

            now = s.now()
            built: List[Attachment] = []
            if attachments:
                for filename, data in attachments:
                    built.append(
                        Attachment(
                            filename=filename,
                            size=len(data),
                            uploaded_by=author_id,
                            uploaded_at=now,
                        )
                    )
            if (body is None or body == "") and not built:
                raise ValidationError("body required without attachments")

            if parent_id is not None and parent_id not in s.messages:
                raise NotFoundError("parent {0} not found".format(parent_id))

            message = Message(
                id=s.new_id(),
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built,
                created_at=now,
                edited_at=None,
            )
            s.messages[message.id] = message
            if project_id is not None:
                s.messages_by_project.setdefault(project_id, set()).add(message.id)
            if task_id is not None:
                s.messages_by_task.setdefault(task_id, set()).add(message.id)
            return copy.deepcopy(message)

    def edit(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            message = self._get_raw(message_id)
            if editor_id != message.author_id:
                raise AuthorizationError("only the author may edit")
            if (new_body is None or new_body == "") and not message.attachments:
                raise ValidationError("body required without attachments")
            message.body = new_body
            message.edited_at = self._state.now()
            return copy.deepcopy(message)

    def add_attachment(self, message_id, uploader_id, filename, data) -> Message:
        with self._lock:
            message = self._get_raw(message_id)
            if uploader_id != message.author_id:
                raise AuthorizationError("only the author may add attachments")
            _require_non_empty(filename, "filename")
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=uploader_id,
                    uploaded_at=self._state.now(),
                )
            )
            return copy.deepcopy(message)

    def list_by_project(self, project_id: int) -> List[Message]:
        with self._lock:
            s = self._state
            if project_id not in s.projects:
                raise NotFoundError("project {0} not found".format(project_id))
            ids = s.messages_by_project.get(project_id, set())
            ordered = sorted((s.messages[i] for i in ids), key=lambda m: m.id)
            return [copy.deepcopy(m) for m in ordered]

    def list_by_task(self, task_id: int) -> List[Message]:
        with self._lock:
            s = self._state
            if task_id not in s.tasks:
                raise NotFoundError("task {0} not found".format(task_id))
            ids = s.messages_by_task.get(task_id, set())
            ordered = sorted((s.messages[i] for i in ids), key=lambda m: m.id)
            return [copy.deepcopy(m) for m in ordered]

    def delete(self, message_id, requester_id) -> None:
        with self._lock:
            s = self._state
            message = self._get_raw(message_id)
            if requester_id != message.author_id:
                raise AuthorizationError("only the author may delete")
            del s.messages[message_id]
            if message.project_id is not None:
                bucket = s.messages_by_project.get(message.project_id)
                if bucket is not None:
                    bucket.discard(message_id)
            if message.task_id is not None:
                bucket = s.messages_by_task.get(message.task_id)
                if bucket is not None:
                    bucket.discard(message_id)


# ---------------------------------------------------------------------------
# Performance service
# ---------------------------------------------------------------------------
class _PerformanceService:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def _require_user(self, user_id: int) -> None:
        if user_id not in self._state.users:
            raise NotFoundError("user {0} not found".format(user_id))

    def _assigned_tasks(self, user_id: int) -> List[Task]:
        s = self._state
        ids = s.tasks_by_assignee.get(user_id, set())
        return [s.tasks[i] for i in ids if i in s.tasks]

    def completion_rate(self, user_id: int) -> float:
        with self._lock:
            self._require_user(user_id)
            tasks = self._assigned_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def average_completion_time(self, user_id: int) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            durations = []
            for t in self._assigned_tasks(user_id):
                if (t.status == TaskStatus.COMPLETED and t.started_at is not None
                        and t.completed_at is not None):
                    durations.append((t.completed_at - t.started_at).total_seconds())
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None) -> Rating:
        with self._lock:
            s = self._state
            if rater_id not in s.users:
                raise NotFoundError("rater {0} not found".format(rater_id))
            if ratee_id not in s.users:
                raise NotFoundError("ratee {0} not found".format(ratee_id))
            if rater_id == ratee_id:
                raise ConflictError("cannot rate yourself")
            if not isinstance(score, int) or isinstance(score, bool) or not (1 <= score <= 5):
                raise ValidationError("score must be an integer in 1..5")
            if task_id is not None and task_id not in s.tasks:
                raise NotFoundError("task {0} not found".format(task_id))
            rating = Rating(
                id=s.new_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback,
                task_id=task_id,
                created_at=s.now(),
            )
            s.ratings[rating.id] = rating
            s.ratings_by_ratee.setdefault(ratee_id, set()).add(rating.id)
            return copy.deepcopy(rating)

    def _ratings_for(self, user_id: int) -> List[Rating]:
        s = self._state
        ids = s.ratings_by_ratee.get(user_id, set())
        ordered = sorted((s.ratings[i] for i in ids), key=lambda r: r.id)
        return ordered

    def ratings_summary(self, user_id: int) -> dict:
        with self._lock:
            self._require_user(user_id)
            ratings = self._ratings_for(user_id)
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count else 0.0
            return {
                "count": count,
                "average": average,
                "ratings": [copy.deepcopy(r) for r in ratings],
            }

    def user_dashboard(self, user_id: int) -> dict:
        with self._lock:
            self._require_user(user_id)
            tasks = self._assigned_tasks(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )
            return {
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completed / total if total else 0.0,
                "average_completion_time": self.average_completion_time(user_id),
                "rating_count": rating_count,
                "rating_average": rating_average,
            }


# ---------------------------------------------------------------------------
# Reports service
# ---------------------------------------------------------------------------
class _ReportsService:
    def __init__(self, state: _State, performance: _PerformanceService):
        self._state = state
        self._lock = state.lock
        self._performance = performance

    def _require_project(self, project_id: int) -> Project:
        project = self._state.projects.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _require_user(self, user_id: int) -> User:
        user = self._state.users.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _status_breakdown(self, tasks: List[Task]) -> dict:
        counts = {status.value: 0 for status in TaskStatus}
        for t in tasks:
            counts[t.status.value] += 1
        return counts

    def _user_metrics(self, user_id: int) -> dict:
        s = self._state
        ids = s.tasks_by_assignee.get(user_id, set())
        tasks = [s.tasks[i] for i in ids if i in s.tasks]
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
        not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
        user = s.users.get(user_id)
        ratings = self._performance._ratings_for(user_id)
        rating_count = len(ratings)
        rating_average = (
            sum(r.score for r in ratings) / rating_count if rating_count else 0.0
        )
        return {
            "user_id": user_id,
            "username": user.username if user else None,
            "total_tasks": total,
            "completed_tasks": completed,
            "in_progress_tasks": in_progress,
            "not_started_tasks": not_started,
            "completion_rate": completed / total if total else 0.0,
            "average_completion_time": self._performance.average_completion_time(user_id),
            "rating_count": rating_count,
            "rating_average": rating_average,
        }

    def project_progress(self, project_id: int) -> dict:
        with self._lock:
            s = self._state
            self._require_project(project_id)
            ids = s.tasks_by_project.get(project_id, set())
            tasks = [s.tasks[i] for i in ids if i in s.tasks]
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            now = s.now()
            overdue = sum(
                1
                for t in tasks
                if t.deadline is not None
                and t.deadline < now
                and t.status != TaskStatus.COMPLETED
            )
            per_assignee = {}
            assignees = {t.assignee_id for t in tasks if t.assignee_id is not None}
            for assignee_id in assignees:
                per_assignee[assignee_id] = self._user_metrics(assignee_id)
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": self._status_breakdown(tasks),
                "completion_rate": completed / total if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance(self, project_id=None) -> dict:
        with self._lock:
            s = self._state
            if project_id is not None:
                self._require_project(project_id)
                ids = s.tasks_by_project.get(project_id, set())
                tasks = [s.tasks[i] for i in ids if i in s.tasks]
                user_ids = sorted(
                    {t.assignee_id for t in tasks if t.assignee_id is not None}
                )
            else:
                user_ids = sorted(s.users.keys())
            rows = [self._user_metrics(uid) for uid in user_ids]
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "rows": rows,
            }

    def individual_performance(self, user_id: int) -> dict:
        with self._lock:
            s = self._state
            self._require_user(user_id)
            metrics = self._user_metrics(user_id)
            ids = s.tasks_by_assignee.get(user_id, set())
            ordered = sorted((s.tasks[i] for i in ids if i in s.tasks),
                             key=lambda t: t.id)
            tasks = [
                {
                    "id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "deadline": t.deadline,
                    "started_at": t.started_at,
                    "completed_at": t.completed_at,
                }
                for t in ordered
            ]
            report = {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
            }
            report.update(metrics)
            report["tasks"] = tasks
            return report

    # -- Export -----------------------------------------------------------
    @staticmethod
    def _cell(value) -> str:
        if value is None:
            return ""
        if isinstance(value, Enum):
            return str(value.value)
        return str(value)

    def _report_to_rows(self, report: dict) -> List[List[str]]:
        report_type = report.get("report_type")
        if report_type == ReportType.TEAM_PERFORMANCE.value:
            header = [
                "user_id", "username", "total_tasks", "completed_tasks",
                "in_progress_tasks", "not_started_tasks", "completion_rate",
                "average_completion_time", "rating_count", "rating_average",
            ]
            rows = [header]
            for entry in report.get("rows", []):
                rows.append([self._cell(entry.get(col)) for col in header])
            return rows
        if report_type == ReportType.INDIVIDUAL_PERFORMANCE.value:
            header = [
                "id", "title", "status", "deadline", "started_at", "completed_at",
            ]
            rows = [header]
            for task in report.get("tasks", []):
                rows.append([self._cell(task.get(col)) for col in header])
            return rows
        # PROJECT_PROGRESS / fallback: flatten scalars, expand nested dicts.
        rows = [["metric", "value"]]
        for key, value in report.items():
            if isinstance(value, dict):
                for sub_key, sub_value in value.items():
                    rows.append(
                        ["{0}.{1}".format(key, sub_key), self._cell(sub_value)]
                    )
            elif isinstance(value, (list, tuple)):
                rows.append([self._cell(key), self._cell(len(value))])
            else:
                rows.append([self._cell(key), self._cell(value)])
        return rows

    def export(self, report, report_format):
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict")
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("report_format must be a ReportFormat")
        rows = self._report_to_rows(report)
        if report_format == ReportFormat.CSV:
            return self._to_csv(rows)
        if report_format == ReportFormat.PDF:
            return self._to_pdf(rows)
        raise ValidationError("unsupported report format")

    @staticmethod
    def _to_csv(rows: List[List[str]]) -> str:
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        for row in rows:
            writer.writerow(row)
        return buffer.getvalue()

    @staticmethod
    def _pdf_escape(text: str) -> str:
        return text.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")

    def _to_pdf(self, rows: List[List[str]]) -> bytes:
        lines = [" | ".join(row) for row in rows]
        if not lines:
            lines = [""]

        content_parts = ["BT", "/F1 12 Tf", "12 TL", "50 770 Td"]
        for index, line in enumerate(lines):
            escaped = self._pdf_escape(line)
            if index == 0:
                content_parts.append("({0}) Tj".format(escaped))
            else:
                content_parts.append("T* ({0}) Tj".format(escaped))
        content_parts.append("ET")
        content_stream = "\n".join(content_parts)
        content_bytes = content_stream.encode("ascii", "replace")

        objects = []
        objects.append(b"<< /Type /Catalog /Pages 2 0 R >>")
        objects.append(b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>")
        objects.append(
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
        )
        objects.append(
            b"<< /Length "
            + str(len(content_bytes)).encode("ascii")
            + b" >>\nstream\n"
            + content_bytes
            + b"\nendstream"
        )
        objects.append(
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>"
        )

        out = bytearray()
        out += b"%PDF-1.4\n"
        offsets = []
        for index, body in enumerate(objects, start=1):
            offsets.append(len(out))
            out += "{0} 0 obj\n".format(index).encode("ascii")
            out += body
            out += b"\nendobj\n"

        xref_pos = len(out)
        count = len(objects) + 1
        out += "xref\n0 {0}\n".format(count).encode("ascii")
        out += b"0000000000 65535 f \n"
        for offset in offsets:
            out += "{0:010d} 00000 n \n".format(offset).encode("ascii")
        out += (
            "trailer\n<< /Size {0} /Root 1 0 R >>\nstartxref\n{1}\n%%EOF\n"
            .format(count, xref_pos).encode("ascii")
        )
        return bytes(out)


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Facade exposing all team collaboration operations.

    Delegates to repository/service objects that share a single ``_State``
    (and therefore a single reentrant lock and id counter).
    """

    def __init__(self, now: Optional[Callable[[], datetime]] = None):
        self._state = _State(now if now is not None else datetime.now)
        self._lock = self._state.lock

        self.users = _UserRepository(self._state)
        self.projects = _ProjectRepository(self._state)
        self.tasks = _TaskRepository(self._state)
        self.messages = _MessageRepository(self._state)
        self.performance = _PerformanceService(self._state)
        self.reports = _ReportsService(self._state, self.performance)

    # -- Users ------------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        return self.users.register(username, email, role)

    def get_user(self, user_id) -> User:
        return self.users.get(user_id)

    def list_users(self) -> List[User]:
        return self.users.list()

    def update_user(self, user_id, username=UNSET, email=UNSET, role=UNSET) -> User:
        return self.users.update(user_id, username=username, email=email, role=role)

    def delete_user(self, user_id) -> None:
        return self.users.delete(user_id)

    # -- Projects ---------------------------------------------------------
    def create_project(self, name, start_date, end_date, owner_id, description="") -> Project:
        return self.projects.create(name, start_date, end_date, owner_id, description)

    def get_project(self, project_id) -> Project:
        return self.projects.get(project_id)

    def list_projects(self) -> List[Project]:
        return self.projects.list()

    def update_project(self, project_id, name=UNSET, description=UNSET,
                       start_date=UNSET, end_date=UNSET) -> Project:
        return self.projects.update(
            project_id, name=name, description=description,
            start_date=start_date, end_date=end_date,
        )

    def delete_project(self, project_id) -> None:
        return self.projects.delete(project_id)

    # -- Tasks ------------------------------------------------------------
    def create_task(self, project_id, title, assignee_id=None, deadline=None) -> Task:
        return self.tasks.create(project_id, title, assignee_id=assignee_id, deadline=deadline)

    def get_task(self, task_id) -> Task:
        return self.tasks.get(task_id)

    def list_tasks_by_project(self, project_id) -> List[Task]:
        return self.tasks.list_by_project(project_id)

    def list_tasks_by_assignee(self, assignee_id) -> List[Task]:
        return self.tasks.list_by_assignee(assignee_id)

    def assign_task(self, task_id, assignee_id) -> Task:
        return self.tasks.assign(task_id, assignee_id)

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        return self.tasks.reassign(task_id, new_assignee_id)

    def unassign_task(self, task_id) -> Task:
        return self.tasks.unassign(task_id)

    def set_deadline(self, task_id, deadline) -> Task:
        return self.tasks.set_deadline(task_id, deadline)

    def update_status(self, task_id, status) -> Task:
        return self.tasks.update_status(task_id, status)

    # -- Messaging --------------------------------------------------------
    def post_message(self, author_id, body, project_id=None, task_id=None,
                     parent_id=None, attachments=None) -> Message:
        return self.messages.post(
            author_id, body, project_id=project_id, task_id=task_id,
            parent_id=parent_id, attachments=attachments,
        )

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        return self.messages.edit(message_id, editor_id, new_body)

    def add_attachment(self, message_id, uploader_id, filename, data) -> Message:
        return self.messages.add_attachment(message_id, uploader_id, filename, data)

    def list_messages_by_project(self, project_id) -> List[Message]:
        return self.messages.list_by_project(project_id)

    def list_messages_by_task(self, task_id) -> List[Message]:
        return self.messages.list_by_task(task_id)

    def delete_message(self, message_id, requester_id) -> None:
        return self.messages.delete(message_id, requester_id)

    # -- Performance ------------------------------------------------------
    def get_completion_rate(self, user_id) -> float:
        return self.performance.completion_rate(user_id)

    def get_average_completion_time(self, user_id) -> Optional[float]:
        return self.performance.average_completion_time(user_id)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None) -> Rating:
        return self.performance.submit_rating(
            rater_id, ratee_id, score, feedback=feedback, task_id=task_id,
        )

    def get_ratings_summary(self, user_id) -> dict:
        return self.performance.ratings_summary(user_id)

    def get_user_dashboard(self, user_id) -> dict:
        return self.performance.user_dashboard(user_id)

    # -- Reports ----------------------------------------------------------
    def project_progress_report(self, project_id) -> dict:
        return self.reports.project_progress(project_id)

    def team_performance_report(self, project_id=None) -> dict:
        return self.reports.team_performance(project_id)

    def individual_performance_report(self, user_id) -> dict:
        return self.reports.individual_performance(user_id)

    def export_report(self, report, report_format):
        return self.reports.export(report, report_format)
